import type { IStyleClasses } from '@lmb-it/kitsconcerto-types';
import { mapCssProperties } from '@lmb-it/kitsconcerto-types';
import { media } from './media';
import { expandResponsiveValue } from './responsive';
import { isCssValue } from './validate';
import { toCssValue } from './theme';
import { translateCss } from './translate';

/** Generates CSS rules from a translated props object (no pseudo-class handling). */
const buildCssBlock = (translated: Record<string, unknown>): string => {
  let css = '';

  Object.entries(translated).forEach(([key, raw]) => {
    if (raw == null || key.startsWith('_')) return;

    const cssKey = mapCssProperties[key as never];
    if (!cssKey) return;

    const expanded = expandResponsiveValue(raw as any);

    Object.entries(expanded).forEach(([cond, value]) => {
      if (!isCssValue(value, cssKey)) return;

      const rule = `${cssKey}: ${toCssValue(cssKey, value as any)};`;

      if (cond === 'base') {
        css += rule;
        return;
      }

      if (cond.includes(':')) {
        const [a, b] = cond.split(':');
        css += `${media[a!]} { ${media[b!] ?? ''} { ${rule} } }`;
      } else {
        css += `${media[cond]} { ${rule} }`;
      }
    });
  });

  return css;
};

/**
 * Pseudo-class map: prop name → CSS selector(s).
 * Each entry generates &:selector { ... } in the styled-component output.
 */
const PSEUDO_MAP: Record<string, string> = {
  _hover:        '&:hover',
  _focus:        '&:focus, &:focus-within',
  _focusVisible: '&:focus-visible',
  _active:       '&:active',
  _disabled:     '&:disabled, &[aria-disabled="true"]',
  _visited:      '&:visited',
  _checked:      '&:checked',
  _placeholder:  '&::placeholder',
  _selection:    '&::selection',
  _firstChild:   '&:first-child',
  _lastChild:    '&:last-child',
};

/** Generates a complete CSS string from style-class props, including pseudo-classes. */
export const style = (props: IStyleClasses, id: string | undefined = ''): string => {
  const translated = translateCss(props, id);

  let css = buildCssBlock(translated);

  // Process all pseudo-class props
  for (const [propKey, selector] of Object.entries(PSEUDO_MAP)) {
    const pseudoProps = (props as any)?.[propKey];
    if (pseudoProps && typeof pseudoProps === 'object') {
      const pseudoCss = buildCssBlock(translateCss(pseudoProps as IStyleClasses));
      if (pseudoCss) css += `${selector} { ${pseudoCss} }`;
    }
  }

  return css;
};
